        "url": "/%D1%82%D1%80%D0%B8-%D0%BF%D1%80%D0%B8%D1%87%D0%B8%D0%BD%D0%B8-%D0%B4%D0%B0-%D1%83%D0%B4%D1%8A%D0%BB%D0%B6%D0%B8%D1%82%D0%B5-%D0%BA%D0%BE%D1%81%D0%B0%D1%82%D0%B0-%D1%81%D0%B8/",
        "teaser": "/assets/images/hair_image.jpeg"
